enum Direction {
    North,
    South,
    East,
    West,
}

fn describe(d: Direction) {
    match d {
        Direction::North => println!("Going north"),
        Direction::South => println!("Going south"),
        Direction::East  => println!("Going east"),
        Direction::West  => println!("Going west"),
    }
}

fn main() {
    describe(Direction::North);
    describe(Direction::East);
}

enum Shape {
    Circle(f64),
    Rectangle(f64, f64),
}

fn area(s: Shape) -> f64 {
    match s {
        Shape::Circle(r) => std::f64::consts::PI * r * r,
        Shape::Rectangle(w, h) => w * h,
    }
}

fn main() {
    println!("{:.2}", area(Shape::Circle(3.0)));
    println!("{:.2}", area(Shape::Rectangle(4.0, 5.0)));
}

fn divide(a: f64, b: f64) -> Option<f64> {
    if b == 0.0 { None } else { Some(a / b) }
}

fn main() {
    println!("{:?}", divide(10.0, 2.0));
    println!("{:?}", divide(10.0, 0.0));
}

fn main() {
    let v = vec![1, 2, 3];
    let first = v.first(); // Option<&i32>
    println!("{}", first.unwrap());

    let empty: Vec<i32> = vec![];
    println!("{:?}", empty.first()); // None
}

fn find_first_even(nums: &[i32]) -> Option<i32> {
    for &n in nums {
        if n % 2 == 0 { return Some(n); }
    }
    None
}

fn main() {
    let v = [1, 3, 4, 7, 8];
    if let Some(n) = find_first_even(&v) {
        println!("first even: {}", n);
    } else {
        println!("no even numbers");
    }
}

fn main() {
    let some_val: Option<i32> = Some(42);
    let none_val: Option<i32> = None;

    println!("{}", some_val.unwrap_or(0));
    println!("{}", none_val.unwrap_or(0));
    println!("{}", none_val.unwrap_or_else(|| 99));
}

fn main() {
    let maybe: Option<i32> = Some(5);
    let doubled = maybe.map(|x| x * 2);
    println!("{:?}", doubled);

    let result = Some("42")
        .and_then(|s| s.parse::<i32>().ok());
    println!("{:?}", result);
}

fn first_char(s: &str) -> Option<char> {
    let c = s.chars().next()?;
    Some(c.to_ascii_uppercase())
}

fn main() {
    println!("{:?}", first_char("hello"));
    println!("{:?}", first_char(""));
}
